{"formula":"const mapProvider = $map.getMapProvider();
const map = $map.getMapObject();
const bounds = map.getBounds();
let bbox;

// Nettoyage de la couche d'analyse précédente
if (!$context._analysisLayer) $context._analysisLayer = [];
const clearPrevious = () => {
    for (const item of $context._analysisLayer) {
        if (mapProvider === 'Leaflet') item.remove();
        else if (mapProvider === 'GoogleMaps') item.setMap(null);
    }
    $context._analysisLayer = [];
};
clearPrevious();

// Préparation de la BBOX
if (mapProvider === 'Leaflet') {
    const sw = bounds.getSouthWest();
    const ne = bounds.getNorthEast();
    bbox = `${sw.lat},${sw.lng},${ne.lat},${ne.lng}`;
} else {
    const sw = bounds.getSouthWest();
    const ne = bounds.getNorthEast();
    bbox = `${sw.lat()},${sw.lng()},${ne.lat()},${ne.lng()}`;
}

const query = `[out:json][timeout:25];
(
  node["tourism"="camp_site"](${bbox});
  way["tourism"="camp_site"](${bbox});
  relation["tourism"="camp_site"](${bbox});
);
out center;`;

try {
    const response = await fetch("https://overpass-api.de/api/interpreter", {
        method: "POST",
        body: query
    });
    const data = await response.json();
    const results = data.elements || [];

    const campsiteData = results.map(el => {
        const tags = el.tags || {};

        // Construction de l'adresse
        const addrArr = [
            tags['addr:housenumber'],
            tags['addr:street'],
            tags['addr:postcode'],
            tags['addr:city']
        ].filter(Boolean);
        const fullAddress = addrArr.join(' ') || "Adresse non renseignée";

        // Gestion des étoiles
        const rawStars = tags.stars || tags.official_stars || "";
        const starCount = parseInt(rawStars.replace(/[^0-9]/g, '')) || 0;

        return {
            id: el.id,
            name: tags.name || "Camping sans nom",
            stars: starCount,
            address: fullAddress,
            phone: tags.phone || tags['contact:phone'] || null,
            website: tags.website || tags['contact:website'] || tags.url || null,
            email: tags.email || tags['contact:email'] || null,
            opening: tags.opening_hours || null,
            lat: el.lat || el.center.lat,
            lng: el.lon || el.center.lon
        };
    });

    const renderStars = (count) => {
        if (count === 0) return '';
        let starsHtml = '';
        for (let i = 0; i < count; i++) starsHtml += `<span class="text-warning" style="font-size:0.8rem">${$tools.icon('star-fill')}</span>`;
        return starsHtml;
    };

    // Ajout des marqueurs avec popups riches
    for (const site of campsiteData) {
        const content = `
            <div style="width: 200px; font-size: 0.9rem;">
                <div class="d-flex justify-content-between align-items-start mb-1">
                    <strong>${site.name}</strong>
                </div>
                <div class="mb-1">${renderStars(site.stars)}</div>
                <p class="small text-muted mb-2">${$tools.icon('geo-alt')} ${site.address}</p>
                <div class="d-flex flex-column gap-1">
                    ${site.phone ? `<a href="tel:${site.phone}" class="btn btn-sm btn-light mb-1">${$tools.icon('telephone')} ${site.phone}</a>` : ''}
                    ${site.website ? `<a href="${site.website}" target="_blank" class="btn btn-sm btn-primary text-white">${$tools.icon('globe')} Site Web</a>` : ''}
                </div>
            </div>
        `;

        if (mapProvider === 'Leaflet') {
            const marker = L.marker([site.lat, site.lng]).addTo(map);
            marker.bindPopup(content);
            $context._analysisLayer.push(marker);
        } else {
            const marker = new google.maps.Marker({
                position: { lat: site.lat, lng: site.lng },
                map: map,
                title: site.name
            });
            const infoWindow = new google.maps.InfoWindow({ content: content });
            marker.addListener("click", () => infoWindow.open(map, marker));
            $context._analysisLayer.push(marker);
        }
    }

    const rows = campsiteData.map(site => `
        <tr class="small">
            <td>
                <div class="font-weight-bold">${site.name}</div>
                <div class="text-muted" style="font-size:0.75rem">${site.address}</div>
            </td>
            <td class="text-nowrap">${renderStars(site.stars)}</td>
            <td class="text-right">
                <div class="btn-group">
                    ${site.website ? `<a href="${site.website}" target="_blank" class="btn btn-sm btn-outline-secondary" title="Site Web">${$tools.icon('globe')}</a>` : ''}
                    ${site.phone ? `<a href="tel:${site.phone}" class="btn btn-sm btn-outline-secondary" title="Appeler">${$tools.icon('telephone')}</a>` : ''}
                    <button class="btn btn-sm btn-info fly-to-btn" data-lat="${site.lat}" data-lng="${site.lng}">${$tools.icon('cursor')}</button>
                </div>
            </td>
        </tr>
    `).join('');

    const html = `
        <div class="card shadow-sm">
            <div class="card-header bg-dark text-white py-2 d-flex justify-content-between align-items-center">
                <h6 class="mb-0">${$tools.icon('info-circle')} Détails des Campings (${campsiteData.length})</h6>
            </div>
            <div class="table-responsive" style="max-height: 350px;">
                <table class="table table-sm table-hover align-middle mb-0">
                    <thead class="thead-light">
                        <tr>
                            <th>Établissement & Adresse</th>
                            <th>Stars</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>${rows || '<tr><td colspan="3" class="text-center p-3">Aucune donnée disponible</td></tr>'}</tbody>
                </table>
            </div>
        </div>
    `;

    requestAnimationFrame(() => {
        document.querySelectorAll('.fly-to-btn').forEach(btn => {
            btn.onclick = () => {
                const lat = parseFloat(btn.getAttribute('data-lat'));
                const lng = parseFloat(btn.getAttribute('data-lng'));
                $map.flyTo({ lat, lng }, 17);
            };
        });
    });

    return {
        html,
        data: campsiteData,
        reset: () => clearPrevious()
    };

} catch (error) {
    console.error("Erreur analyse complète campings", error);
    return { html: `<div class="alert alert-danger">${error.message}</div>`, data: [], reset: () => clearPrevious() };
}","description":"Analyse exhaustive des campings à proximité incluant l'extraction de l'adresse, du téléphone, de l'e-mail, du site web et du classement en étoiles. Les résultats sont interactifs sur la carte et via un tableau de bord de contact.","title":"Annuaire Complet des Campings","output":"{
  "data": [
    {
      "id": "number",
      "name": "string",
      "stars": "number",
      "address": "string",
      "phone": "string|null",
      "website": "string|null",
      "email": "string|null",
      "opening": "string|null",
      "lat": "number",
      "lng": "number"
    }
  ]
}","mode":"SINGLE-POINT"}
